('p_082529', 'PHRASE', 'at once', 'na. 立刻；同时', 5, 'new_concept', '["CET4", "CET6", "IELTS", "NCE", "TOEFL", "advanced", "beibei", "expert", "gaokao", "junior", "kaoyan", "momo", "primary", "senior", "zhongkao"]', '[{"en":"Return at once.","zh":"马上回来。"},{"en":"She came at once.","zh":"Tā lìkè jiù láile. 她立刻就来了。"},{"en":"I''ll be there at once.","zh":"我會立刻到那裡。"}]'),
