('p_083326', 'PHRASE', 'in a minute', 'na. 马上', 5, 'phrases', '["CET4", "CET6", "IELTS", "advanced", "beibei", "expert", "gaokao", "junior", "momo", "primary", "senior", "zhongkao"]', '[{"en":"I''ll be there in a minute.","zh":"我马上就到了。"},{"en":"Coming! I''ll be there in a minute!","zh":"马上！我就来！"},{"en":"Tell Tom I''ll be there in a minute.","zh":"告诉Tom我将在一分钟内到达这里。"}]'),
