('p_083331', 'PHRASE', 'in a word', 'na. “in a few words”的变体\n 总之；简言之；总而言之', 5, 'phrases', '["CET4", "CET6", "IELTS", "TEM4", "TOEFL", "advanced", "beibei", "expert", "gaokao", "junior", "kaoyan", "momo", "primary", "senior", "zhongkao"]', '[{"en":"In a word, life is short.","zh":"总而言之，生命是很短的。"},{"en":"In a word, you hate me, don''t you?","zh":"简而言之，你恨我，是吧？"}]'),
('p_083332', 'PHRASE', 'in abundance', 'adv. 充足', 5, 'phrases', '["CET4", "CET6", "advanced", "beibei", "expert", "kaoyan", "momo"]', '[{"en":"She lives in abundance.","zh":"她过着富足的日子。"}]'),
