('p_083747', 'PHRASE', 'out of breath', '运动后喘不上气；透不过气来', 5, 'senior_high', '["CET4", "CET6", "NCE", "advanced", "beibei", "expert", "gaokao", "junior", "kaoyan", "momo", "primary", "senior", "zhongkao"]', '[{"en":"He was out of breath.","zh":"他气喘吁吁的。"},{"en":"He ran so fast that he was out of breath.","zh":"他跑得太快，以至於喘不過氣來。"},{"en":"After running up the hill, I was completely out of breath.","zh":"跑上山後，我完全喘不過氣來。"}]'),
('p_083748', 'PHRASE', 'out of control', '无法管理；失去控制', 5, 'college_english', '["CET4", "CET6", "IELTS", "advanced", "beibei", "expert", "gaokao", "junior", "kaoyan", "momo", "primary", "senior", "zhongkao"]', '[{"en":"The robot went out of control.","zh":"這個機器人失控了。"},{"en":"He is out of control when drunk.","zh":"他會酒後失控。"},{"en":"Things are getting out of control.","zh":"事情要失控了。"}]'),
