('p_083750', 'PHRASE', 'out of sight', '在视野之外；在看不见的地方', 5, 'college_english', '["CET4", "CET6", "IELTS", "TOEFL", "advanced", "beibei", "expert", "gaokao", "kaoyan", "momo", "senior"]', '[{"en":"Out of sight, out of mind.","zh":"眼不见，心不烦。"},{"en":"The plane took off and was soon out of sight.","zh":"飛機起飛後，很快就消失在了眼前。"},{"en":"She waved her hand until the train was out of sight.","zh":"她挥着她的手，直到火车消失在视线之外。"}]'),
