('p_084041', 'PHRASE', 'take away', 'adj. 买回去的', 5, 'junior_high', '["CET4", "CET6", "IELTS", "TOEFL", "advanced", "beibei", "expert", "gaokao", "junior", "kaoyan", "momo", "primary", "senior", "zhongkao"]', '[{"en":"The doctor has given her some tablets to take away the pain.","zh":"医生给了她一些止疼药片。"},{"en":"Worrying doesn''t take away tomorrow''s concerns, but it does take away today''s power.","zh":"煩惱帶不走明天的憂慮, 但卻拿走了今天的力量。"},{"en":"If you''re going to say it, you have to say it with force, and take away your opponent''s ability to retaliate.","zh":"要说，就要说得有力量，使对方失去反驳的能力。"}]'),
('p_084042', 'PHRASE', 'take care', '告别用语；走好保重', 5, 'junior_high', '["CET4", "CET6", "TOEFL", "advanced", "beibei", "expert", "gaokao", "junior", "kaoyan", "momo", "primary", "senior", "zhongkao"]', '[{"en":"I''ll take care of it.","zh":"我會關照它的。"},{"en":"I''ll take care of you.","zh":"我会照顾你。"},{"en":"Take care not to fail.","zh":"注意别失败。"}]'),
